def extract_bearer_token():
    """Extract the bearer token from the Authorization header or query parameter."""
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()
    # Fallback: check query parameter (not recommended for production)
    return request.args.get('access_token')


def validate_token(token_string):
    """Look up and validate an access token from the database.

    Returns the AccessToken instance if valid, otherwise None.
    """
    if not token_string:
        return None

    token_record = AccessToken.query.filter_by(token=token_string).first()
    if token_record is None:
        return None

    if not token_record.is_valid():
        return None

    return token_record


