@app.route('/oauth/token', methods=['POST'])
def issue_token():
    """Issue an access token via client_credentials or refresh_token grant.

    This is a simplified token endpoint suitable for service-to-service auth.
    """
    grant_type = request.form.get('grant_type')

    if grant_type == 'client_credentials':
        client_id = request.form.get('client_id')
        client_secret = request.form.get('client_secret')
        requested_scopes = request.form.get('scope', '').split()

        if not client_id or not client_secret:
            return jsonify({'error': 'invalid_request', 'error_description': 'Missing client credentials.'}), 400

        client = OAuthClient.query.filter_by(client_id=client_id).first()
        if client is None or client.client_secret != client_secret or not client.is_active:
            log_audit('token_issue_failure', client_id=client_id, details='Bad client credentials')
            return jsonify({'error': 'invalid_client', 'error_description': 'Invalid client credentials.'}), 401

        # Validate requested scopes against allowed scopes
        allowed = client.get_allowed_scopes()
        granted_scopes = [s for s in requested_scopes if s in allowed] if requested_scopes else allowed

        token_value = secrets.token_urlsafe(48)
        expires_at = datetime.now(timezone.utc) + timedelta(hours=1)

        access_token = AccessToken(
            token=token_value,
            client_id=client.client_id,
            scopes=' '.join(granted_scopes),
            expires_at=expires_at,
        )
        db.session.add(access_token)
        db.session.flush()

        refresh_token_value = secrets.token_urlsafe(48)
        refresh_token = RefreshToken(
            token=refresh_token_value,
            access_token_id=access_token.id,
        )
        db.session.add(refresh_token)
        db.session.commit()

        log_audit('token_issued', client_id=client.client_id, details=f'scopes={granted_scopes}')

        return jsonify({
            'access_token': token_value,
            'token_type': 'Bearer',
            'expires_in': 3600,
            'scope': ' '.join(granted_scopes),
            'refresh_token': refresh_token_value,
        })

    elif grant_type == 'refresh_token':
        refresh_token_value = request.form.get('refresh_token')
        if not refresh_token_value:
            return jsonify({'error': 'invalid_request', 'error_description': 'Missing refresh token.'}), 400

        refresh_record = RefreshToken.query.filter_by(token=refresh_token_value, revoked=False).first()
        if refresh_record is None:
            return jsonify({'error': 'invalid_grant', 'error_description': 'Invalid refresh token.'}), 400

        old_access = refresh_record.access_token
        client = OAuthClient.query.filter_by(client_id=old_access.client_id).first()
        if client is None or not client.is_active:
            return jsonify({'error': 'invalid_client', 'error_description': 'Client is no longer active.'}), 401

        # Revoke old tokens
        old_access.revoked = True
        refresh_record.revoked = True

        new_token_value = secrets.token_urlsafe(48)
        expires_at = datetime.now(timezone.utc) + timedelta(hours=1)

        new_access = AccessToken(
            token=new_token_value,
            client_id=client.client_id,
            user_id=old_access.user_id,
            scopes=old_access.scopes,
            expires_at=expires_at,
        )
        db.session.add(new_access)
        db.session.flush()

        new_refresh_value = secrets.token_urlsafe(48)
        new_refresh = RefreshToken(token=new_refresh_value, access_token_id=new_access.id)
        db.session.add(new_refresh)
        db.session.commit()

        log_audit('token_refreshed', client_id=client.client_id)

        return jsonify({
            'access_token': new_token_value,
            'token_type': 'Bearer',
            'expires_in': 3600,
            'scope': new_access.scopes,
            'refresh_token': new_refresh_value,
        })

    return jsonify({'error': 'unsupported_grant_type'}), 400


