@app.route('/oauth/revoke', methods=['POST'])
def revoke_token():
    """Revoke an access or refresh token (RFC 7009)."""
    token_value = request.form.get('token')
    token_type_hint = request.form.get('token_type_hint', 'access_token')

    if not token_value:
        return jsonify({'error': 'invalid_request', 'error_description': 'Missing token parameter.'}), 400

    if token_type_hint == 'refresh_token':
        record = RefreshToken.query.filter_by(token=token_value).first()
        if record:
            record.revoked = True
            record.access_token.revoked = True
            db.session.commit()
            log_audit('token_revoked', details='refresh_token revoked')
    else:
        record = AccessToken.query.filter_by(token=token_value).first()
        if record:
            record.revoked = True
            # Also revoke associated refresh tokens
            for rt in RefreshToken.query.filter_by(access_token_id=record.id).all():
                rt.revoked = True
            db.session.commit()
            log_audit('token_revoked', client_id=record.client_id, details='access_token revoked')

    # Per RFC 7009, always return 200 even if token was not found
    return jsonify({'status': 'ok'}), 200


