@app.route('/oauth/introspect', methods=['POST'])
def introspect_token():
    """Token introspection endpoint for other microservices to validate tokens."""
    token_value = request.form.get('token')
    if not token_value:
        return jsonify({'active': False}), 200

    token_record = AccessToken.query.filter_by(token=token_value).first()
    if token_record is None or not token_record.is_valid():
        return jsonify({'active': False}), 200

    return jsonify({
        'active': True,
        'scope': token_record.scopes,
        'client_id': token_record.client_id,
        'sub': token_record.user_id,
        'exp': int(token_record.expires_at.replace(tzinfo=timezone.utc).timestamp()),
        'iat': int(token_record.created_at.replace(tzinfo=timezone.utc).timestamp()),
        'token_type': 'Bearer',
    })


